BaseListener = {}
BaseListener.callbacks = {}

function BaseListener.registerCallBack(event, func)
    BaseListener.callbacks[event] = func
end

function BaseListener:destroy()
    BaseListener.callbacks = {}
    Listener.unregisterAll()
end

function BaseListener:init()
    GameDestroyEvent.unregisterAll()
    GameInitEvent.unregisterAll()
    GameInitEvent.registerCallBack(self.onGameInit)
    GameDestroyEvent.registerCallBack(self.onGameDestroy)
end

function BaseListener.onGameInit(gameType)
    GameType = gameType
    BaseMain:setGameType(gameType)
    AnalyticsListener:init()
    ExchangeHelper:init()
    Listener.registerCallBack(LuaHotUpdateEvent, BaseListener.onLuaHotUpdate)
    Listener.registerCallBack(GameLoadMapSuccessEvent, BaseListener.onGameLoadMapSuccess)
    Listener.registerCallBack(LuaLoadWorldEndEvent, BaseListener.onLuaLoadWorldEnd)
    Listener.registerCallBack(GameReadyEvent, BaseListener.onGameReady)
    Listener.registerCallBack(ServerCommonDataEvent, BaseListener.onServerCommonData)
    Listener.registerCallBack(GameMainTickEvent, BaseListener.onGameMainTick)
    Listener.registerCallBack(HideAllLayoutEvent, BaseListener.onHideAllLayout)
    Listener.registerCallBack(RecoverAllLayoutEvent, BaseListener.onRecoverAllLayout)
    Listener.registerCallBack(ShowPluginLayoutEvent, BaseListener.onShowPluginLayout)
    Listener.registerCallBack(GameActionTriggerEvent, BaseListener.onGameActionTrigger)
    Listener.registerCallBack(SpawnEntityEvent, BaseListener.onSpawnEntity)
    Listener.registerCallBack(RemoveEntityEvent, BaseListener.onRemoveEntity)
    Listener.registerCallBack(OtherPlayerSpawnEvent, BaseListener.onOtherPlayerSpawn)
    Listener.registerCallBack(PlayerRebirthEvent, BaseListener.onPlayerRebirth)
    Listener.registerCallBack(PlayerLoginEvent, BaseListener.onPlayerLogin)
    Listener.registerCallBack(PlayerLogoutEvent, BaseListener.onPlayerLogout)
    Listener.registerCallBack(LuaPlayerDeathEvent, BaseListener.onPlayerDeath)
    Listener.registerCallBack(GameOverEvent, BaseListener.onGameOver)

    if Game:isOpenGM() then
        ---测试服
        require "base.helper.GMHelper"
    end

    local callback = BaseListener.callbacks[GameInitEvent]
    if callback then
        callback()
    end

    if Platform.isWindow() then
        local path = string.gsub(FileUtil:getScriptPath(), "ClientGame", "BaseGame")
        HU.Init("base.hotupdate.hotupdatelist", { ".\\Media\\Scripts\\ClientGame\\Common", FileUtil:getScriptPath(), path })
        LuaTimer:scheduleTimer(function()
            HU.Update()
        end, 1000)
    end
end

function BaseListener.onLuaHotUpdate()
    if HU then
        HU.Update()
    end
    return true
end

function BaseListener.onGameLoadMapSuccess(mapPath, rootPath)
    FileUtil:setMapPath(mapPath)
