function BaseListener.onGameDestroy()
    local callback = BaseListener.callbacks[GameDestroyEvent]
    if callback then
        local result, info = pcall(callback)
        if not result then
            LogUtil.log(info, LogUtil.LogLevel.Error)
        end
    end
    WebService:destroy()
    DataBuilderProcessor:clearMapping()
    CommonDataEvents:unregisterAll()
    GameAnalyticsCache:destroy()
    BaseListener:destroy()
    LuaTimer:cancelAll()
    Game:destroy()
    Lang:destroy()
    PlayerManager:destroy()
    TaskQueueManager:destroy()
    EntityCache:destroy()
    PacketSender:destroy()
    PlayerWallet:destroy()
    GUIManager:destroy()
    MemoryPool.clearPool()
    BaseMain:destroy()
    GameAnalytics.Enable = false
end

function BaseListener.onServerCommonData(key, data)
    CommonDataEvents:dispatchEvent(key, data)
end

function BaseListener.onGameMainTick(frameTime)
    GUIManager:onTick(frameTime)
    LuaTimer:onTick(frameTime)
    EntityCache:onTick(frameTime)
    GameAnalyticsCache:trySendEvents()

    local callback = BaseListener.callbacks[GameMainTickEvent]
    if callback then
        callback(frameTime)
    end
end

function BaseListener.onHideAllLayout()
    GUIManager:hideAllLayout()
end

function BaseListener.onRecoverAllLayout()

end

function BaseListener.onShowPluginLayout(name, params)
    local layout = GUIManager:getLayout(name)
    if not layout then
        return
    end
    layout:show(params)
end

function BaseListener.onGameActionTrigger(type, params)
    if type == 3 then
        PayHelper.disableRecharge()
    end
    local callback = BaseListener.callbacks[GameActionTriggerEvent]
    if callback then
        callback(type, params)
    end
end

function BaseListener.onOtherPlayerSpawn(otherPlayerMP)
    local player = PlayerManager:getPlayerByPlayerMP(otherPlayerMP)
    if not player then
        player = PlayerManager:createOtherPlayer(otherPlayerMP)
    else
        player:onSpawn(otherPlayerMP)
    end
    local callback = BaseListener.callbacks[OtherPlayerSpawnEvent]
    if callback then
        callback(player)
    end
end

function BaseListener.onPlayerRebirth(playerSPMP)
    if not PlayerManager:getClientPlayer() then
        PlayerManager:createClientPlayer()
    else
        PlayerManager:getClientPlayer():onSpawn(playerSPMP)
    end
    local callback = BaseListener.callbacks[PlayerRebirthEvent]
    if callback then
        callback(PlayerManager:getClientPlayer())
    end
end

function BaseListener.onSpawnEntity(entity, type, properties)
    if not EngineWorld:getWorld() then
        return
    end
    local lEntity = EntityCache:createEntityCache(entity, type, properties)
    local callback = BaseListener.callbacks[SpawnEntityEvent]
    if callback then
        callback(lEntity)
    end
end

function BaseListener.onRemoveEntity(entityId)
    EntityCache:removeEntityCache(entityId)
    local callback = BaseListener.callbacks[RemoveEntityEvent]
    if callback then
        callback(entityId)
    end
end

function BaseListener.onPlayerLogin(userId, teamId)

end

function BaseListener.onPlayerLogout(userId)
    local callback = BaseListener.callbacks[PlayerLogoutEvent]
    local player = PlayerManager:getPlayerByUserId(userId)
    if not player then
        return
    end
    if callback then
        callback(player)
    end
    player:onLogout()
    player.Player = nil
    PlayerManager:subPlayer(userId)
end

function BaseListener.onPlayerDeath(userId)
    local player = PlayerManager:getPlayerByUserId(userId)
    if not player then
        return
    end
    player:onSpawn(nil)
end

function BaseListener.onGameOver(message)
    ClientHelper.callAppJsonFunction("onGameOver", { message = message })
    ExchangeHelper:cancelExchangeTimer()
end

return BaseListener
